import { ComprehendClient, DetectDominantLanguageCommand, DetectSentimentCommand } from "@aws-sdk/client-comprehend";
import { TranslateClient, TranslateTextCommand } from "@aws-sdk/client-translate";

const comprehend = new ComprehendClient({region:"us-east-1"});
const translate = new TranslateClient({region:"us-east-1"});

async function analyzeText(text){
  const dl = await comprehend.send(new DetectDominantLanguageCommand({Text: text}));
  const langCode = (dl.Languages?.[0]?.LanguageCode) ?? "en";
  let english = text;
  if (langCode !== "en"){
    const tr = await translate.send(new TranslateTextCommand({Text: text, SourceLanguageCode: langCode, TargetLanguageCode: "en"}));
    english = tr.TranslatedText;
  }
  const sentiment = await comprehend.send(new DetectSentimentCommand({Text: english, LanguageCode: "en"}));
  return { language: langCode, translated: english, sentiment: sentiment.Sentiment };
}
``` 

