const AWS = require('aws-sdk');
const rekognition = new AWS.Rekognition();
const s3 = new AWS.S3();
const dynamodb = new AWS.DynamoDB.DocumentClient();

exports.handler = async (event) => {
  const bucket = event.Records[0].s3.bucket.name;
  const key = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));
  const image = { Image: { S3Object: { Bucket: bucket, Name: key } } };
  const resp = await rekognition.detectLabels({ ...image, MaxLabels: 5 }).promise();
  const labels = resp.Labels.map(l => l.Name);
  const safeFlag = resp.Adult?.Value === false && resp.Violence?.Value === false;
  const report = { objectKey: key, safeFlag, topLabel: labels[0], labels };
  await s3.putObject({ Bucket: bucket, Key: key + '.report.json', Body: JSON.stringify(report) }).promise();
  await dynamodb.put({ TableName: 'ProfileModeration', Item: { userId: '<USER_ID>', objectKey: key, safeFlag, topLabel: labels[0] } }).promise();
  return {};
}
```

