const AWS = require('aws-sdk');
const rek = new AWS.Rekognition();
const s3 = new AWS.S3();

exports.handler = async (event) => {
  const rec = event.Records[0];
  const bucket = rec.s3.bucket.name;
  const key = rec.s3.object.key;
  const resp = await rek.detectLabels({ Image: { S3Object: { Bucket: bucket, Name: key } }, MaxLabels: 10, MinConfidence: 80 }).promise();
  // Build metadata and upload to same bucket
  const labels = resp.Labels.map(l => ({ name: l.Name, conf: l.Confidence }));
  const metadata = { imageKey: key, labels };
  await s3.putObject({ Bucket: bucket, Key: key.replace(/\.[^/.]+$/, '.metadata.json'), Body: JSON.stringify(metadata) }).promise();
  return labels;
};
```

